 1→// components/ui/Card.tsx
 2→// Card subtile — inspirée Linear/Stripe. Pas de shadow, border fine.
 3→
 4→import React from 'react';
 5→
 6→interface CardProps {
 7→  children: React.ReactNode;
 8→  className?: string;
 9→  hover?: boolean;
10→  padding?: 'none' | 'sm' | 'md' | 'lg';
11→}
12→
13→const PADDING = {
14→  none: '',
15→  sm: 'p-4',
16→  md: 'p-5',
17→  lg: 'p-6',
18→};
19→
20→export default function Card({ children, className = '', hover = false, padding = 'md' }: CardProps) {
21→  return (
22→    <div
23→      className={`
24→        bg-white/[0.03] border border-white/[0.06] rounded-xl backdrop-blur-sm
25→        ${PADDING[padding]}
26→        ${hover ? 'hover:border-white/[0.08] hover:bg-white/[0.05] cursor-pointer hover-lift' : ''}
27→        transition-all duration-200
28→        ${className}
29→      `.trim()}
30→    >
31→      {children}
32→    </div>
33→  );
34→}
