  1→@tailwind base;
  2→@tailwind components;
  3→@tailwind utilities;
  4→
  5→/* ═══════════════════════════════════════════════════════════
  6→   DESIGN SYSTEM — CitedBy.ai
  7→   Inspired by Ailoom SaaS Template
  8→   Font: Hikasami Sans (OFL License)
  9→   ═══════════════════════════════════════════════════════════ */
 10→
 11→/* ═══ FONT FACE — Hikasami Sans ═══ */
 12→
 13→@font-face {
 14→  font-family: 'Hikasami';
 15→  src: url('/fonts/Hikasami-VF.woff2') format('woff2-variations');
 16→  font-weight: 100 900;
 17→  font-style: normal;
 18→  font-display: swap;
 19→}
 20→
 21→/* Static fallbacks for browsers without variable font support */
 22→@font-face {
 23→  font-family: 'Hikasami Static';
 24→  src: url('/fonts/Hikasami-Regular.woff2') format('woff2');
 25→  font-weight: 400;
 26→  font-style: normal;
 27→  font-display: swap;
 28→}
 29→@font-face {
 30→  font-family: 'Hikasami Static';
 31→  src: url('/fonts/Hikasami-Medium.woff2') format('woff2');
 32→  font-weight: 500;
 33→  font-style: normal;
 34→  font-display: swap;
 35→}
 36→@font-face {
 37→  font-family: 'Hikasami Static';
 38→  src: url('/fonts/Hikasami-SemiBold.woff2') format('woff2');
 39→  font-weight: 600;
 40→  font-style: normal;
 41→  font-display: swap;
 42→}
 43→@font-face {
 44→  font-family: 'Hikasami Static';
 45→  src: url('/fonts/Hikasami-Bold.woff2') format('woff2');
 46→  font-weight: 700;
