 68→  const rafRef = useRef<number>(0);
 69→  const visibleRef = useRef(true);
 70→  const mouseRef = useRef({ x: 0.5, y: 0.5 });
 71→  const stateRef = useRef<{
 72→    nodes: NetworkNode[];
 73→    particles: Particle[];
 74→    pulses: EnergyPulse[];
 75→    queries: QueryText[];
 76→    brands: BrandResult[];
 77→    queryTimer: number;
 78→    brandTimer: number;
 79→    queryIndex: number;
