 81→    width: number;
 82→    height: number;
 83→    dpr: number;
 84→    reducedMotion: boolean;
 85→    staticDrawn: boolean;
 86→  } | null>(null);
 87→
 88→  // ── Initialize state ──
 89→  const initState = useCallback((w: number, h: number, dpr: number) => {
 90→    const cx = w * 0.5;
 91→    const cy = h * 0.48;
 92→    const nodes: NetworkNode[] = [];
 93→
 94→    // Place nodes in concentric ellipses
 95→    const rings = [
 96→      { count: 6, rx: w * 0.08, ry: h * 0.08, depth: 0.6 },
 97→      { count: 10, rx: w * 0.17, ry: h * 0.15, depth: 0.8 },
 98→      { count: 12, rx: w * 0.27, ry: h * 0.22, depth: 1.0 },
 99→    ];
100→
101→    for (const ring of rings) {
102→      for (let i = 0; i < ring.count; i++) {
103→        const angle = (i / ring.count) * Math.PI * 2 + rand(-0.15, 0.15);
104→        const x = cx + Math.cos(angle) * ring.rx + rand(-15, 15);
105→        const y = cy + Math.sin(angle) * ring.ry + rand(-10, 10);
106→        nodes.push({
107→          x, y, baseX: x, baseY: y,
108→          depth: ring.depth,
