117→    // Build connections (nearest neighbors)
118→    for (let i = 0; i < nodes.length; i++) {
119→      const distances: { idx: number; d: number }[] = [];
120→      for (let j = 0; j < nodes.length; j++) {
121→        if (i === j) continue;
122→        distances.push({ idx: j, d: dist(nodes[i].x, nodes[j].x, nodes[i].y, nodes[j].y) });
123→      }
