125→      const connCount = Math.floor(rand(2, 5));
126→      for (let k = 0; k < Math.min(connCount, distances.length); k++) {
127→        if (!nodes[i].connections.includes(distances[k].idx)) {
128→          nodes[i].connections.push(distances[k].idx);
129→        }
130→        if (!nodes[distances[k].idx].connections.includes(i)) {
131→          nodes[distances[k].idx].connections.push(i);
132→        }
133→      }
134→    }
135→
136→    // Pre-allocate particle pool
137→    const particles: Particle[] = [];
