139→      particles.push({ x: 0, y: 0, vx: 0, vy: 0, targetIdx: 0, life: 0, maxLife: 1, active: false });
140→    }
141→
142→    // Pre-allocate pulse pool
143→    const pulses: EnergyPulse[] = [];
144→    for (let i = 0; i < MAX_PULSES; i++) {
145→      pulses.push({ fromIdx: 0, toIdx: 0, progress: 0, speed: 0, active: false });
146→    }
147→
148→    const reducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
149→
150→    stateRef.current = {
151→      nodes, particles, pulses,
152→      queries: [], brands: [],
153→      queryTimer: 0, brandTimer: 3,
154→      queryIndex: 0, time: 0,
155→      width: w, height: h, dpr,
156→      reducedMotion, staticDrawn: false,
157→    };
158→  }, []);
159→
160→  // ── Spawn particle toward network ──
161→  const spawnParticle = useCallback((x: number, y: number) => {
162→    const s = stateRef.current;
163→    if (!s) return;
164→    for (const p of s.particles) {
165→      if (!p.active) {
166→        p.x = x; p.y = y;
167→        p.targetIdx = Math.floor(rand(0, s.nodes.length));
168→        p.vx = rand(-30, 30);
169→        p.vy = rand(-30, 30);
170→        p.life = 0;
171→        p.maxLife = rand(1.5, 3.5);
