174→      }
175→    }
176→  }, []);
177→
178→  // ── Spawn energy pulse ──
179→  const spawnPulse = useCallback((fromIdx: number) => {
180→    const s = stateRef.current;
181→    if (!s) return;
182→    const node = s.nodes[fromIdx];
183→    if (!node.connections.length) return;
