197→  // ── Update loop ──
198→  const update = useCallback((dt: number) => {
199→    const s = stateRef.current;
200→    if (!s) return;
201→    s.time += dt;
202→
203→    // -- Parallax --
204→    const mx = (mouseRef.current.x - 0.5) * 2;
205→    const my = (mouseRef.current.y - 0.5) * 2;
