265→      p.life += dt;
266→      if (p.life >= p.maxLife) { p.active = false; continue; }
267→
268→      const target = s.nodes[p.targetIdx];
269→      const dx = target.x - p.x;
270→      const dy = target.y - p.y;
271→      const d = Math.sqrt(dx * dx + dy * dy);
272→
273→      // Seek behavior
274→      const seekStrength = Math.min(1, p.life / 0.5) * 200;
