378→    // Layer 2: Network connections
379→    ctx.lineWidth = 1;
380→    for (const node of s.nodes) {
381→      for (const ci of node.connections) {
382→        const other = s.nodes[ci];
383→        const avgBrightness = (node.brightness + other.brightness) / 2;
384→        ctx.strokeStyle = `rgba(168, 85, 247, ${avgBrightness * 0.3})`;
385→        ctx.beginPath();
386→        ctx.moveTo(node.x, node.y);
387→        ctx.lineTo(other.x, other.y);
388→        ctx.stroke();
389→      }
390→    }
391→
392→    // Layer 3: Energy pulses
393→    ctx.globalCompositeOperation = 'lighter';
394→    for (const pulse of s.pulses) {
395→      if (!pulse.active) continue;
396→      const from = s.nodes[pulse.fromIdx];
397→      const to = s.nodes[pulse.toIdx];
398→      const px = lerp(from.x, to.x, pulse.progress);
399→      const py = lerp(from.y, to.y, pulse.progress);
400→      const intensity = Math.sin(pulse.progress * Math.PI);
401→
402→      const pulseGrad = ctx.createRadialGradient(px, py, 0, px, py, 12);
403→      pulseGrad.addColorStop(0, `rgba(168, 85, 247, ${intensity * 0.9})`);
404→      pulseGrad.addColorStop(0.4, `rgba(139, 92, 246, ${intensity * 0.4})`);
405→      pulseGrad.addColorStop(1, 'rgba(139, 92, 246, 0)');
406→      ctx.fillStyle = pulseGrad;
407→      ctx.fillRect(px - 12, py - 12, 24, 24);
408→    }
409→
410→    // Layer 4: Network nodes
411→    for (const node of s.nodes) {
412→      const b = node.brightness;
413→      // Outer glow
414→      const outerGrad = ctx.createRadialGradient(node.x, node.y, 0, node.x, node.y, node.radius * 6);
415→      outerGrad.addColorStop(0, `rgba(168, 85, 247, ${b * 0.3})`);
416→      outerGrad.addColorStop(1, 'rgba(168, 85, 247, 0)');
417→      ctx.fillStyle = outerGrad;
418→      ctx.fillRect(node.x - node.radius * 6, node.y - node.radius * 6, node.radius * 12, node.radius * 12);
419→
420→      // Mid glow
421→      const midGrad = ctx.createRadialGradient(node.x, node.y, 0, node.x, node.y, node.radius * 3);
422→      midGrad.addColorStop(0, `rgba(192, 132, 252, ${b * 0.5})`);
423→      midGrad.addColorStop(1, 'rgba(192, 132, 252, 0)');
424→      ctx.fillStyle = midGrad;
425→      ctx.fillRect(node.x - node.radius * 3, node.y - node.radius * 3, node.radius * 6, node.radius * 6);
426→
427→      // Core
428→      ctx.fillStyle = `rgba(233, 213, 255, ${0.3 + b * 0.7})`;
429→      ctx.beginPath();
430→      ctx.arc(node.x, node.y, node.radius, 0, Math.PI * 2);
431→      ctx.fill();
432→    }
433→
434→    // Layer 5: Particles
435→    for (const p of s.particles) {
436→      if (!p.active) continue;
437→      const lifeRatio = 1 - p.life / p.maxLife;
438→      const alpha = lifeRatio * 0.8;
