451→
452→      let alpha = 1;
453→      if (q.phase === 'dissolving') {
454→        alpha = Math.max(0, 1 - q.timer / 0.8);
455→      }
456→
457→      ctx.font = '16px "Inter", system-ui, sans-serif';
458→      ctx.fillStyle = `rgba(192, 132, 252, ${alpha * 0.9})`;
459→      ctx.shadowColor = 'rgba(168, 85, 247, 0.6)';
460→      ctx.shadowBlur = 8;
461→
462→      const displayText = q.phase === 'typing'
