533→  // ── Canvas setup & animation loop ──
534→  useEffect(() => {
535→    const container = containerRef.current;
536→    const canvas = canvasRef.current;
537→    if (!container || !canvas) return;
538→
539→    const ctx = canvas.getContext('2d');
540→    if (!ctx) return;
541→
