546→      const w = rect.width;
547→      const h = CANVAS_HEIGHT;
548→      canvas.width = w * dpr;
549→      canvas.height = h * dpr;
550→      canvas.style.width = `${w}px`;
551→      canvas.style.height = `${h}px`;
