564→    // Mouse move for parallax
565→    const handleMouse = (e: MouseEvent) => {
566→      const rect = container.getBoundingClientRect();
567→      mouseRef.current = {
568→        x: (e.clientX - rect.left) / rect.width,
569→        y: (e.clientY - rect.top) / rect.height,
570→      };
571→    };
572→    container.addEventListener('mousemove', handleMouse);
573→
574→    // Animation loop
575→    let lastTime = performance.now();
576→
577→    const loop = (now: number) => {
578→      rafRef.current = requestAnimationFrame(loop);
579→      if (!visibleRef.current) return;
580→
581→      const s = stateRef.current;
582→      if (!s) return;
