import React, { useRef, useEffect, useCallback } from 'react';

// ── Constants ──
const CANVAS_HEIGHT = 560;
const MAX_PARTICLES = 200;
const MAX_PULSES = 20;
const NODE_COUNT = 28;
const DT_CAP = 0.05; // 50ms max delta

const QUERIES = [
  'Meilleur outil CRM ?',
  'Quel logiciel de comptabilité choisir ?',
  'Top agence SEO en France ?',
  'Meilleure plateforme e-commerce ?',
  'Outil de gestion de projet recommandé ?',
  'Quelle solution emailing utiliser ?',
  'Meilleur hébergeur web ?',
  'Quel ERP pour PME ?',
];

const CITED_BRANDS = ['HubSpot', 'Notion', 'Shopify', 'Mailchimp', 'Semrush', 'Stripe'];
const GHOST_BRANDS = ['BrandX', 'OldCRM', 'FadeTech', 'NoRank', 'Invisible.io', 'Gone SaaS', 'DeadPage', 'ZeroSEO'];

// ── Types ──
interface NetworkNode {
  x: number; y: number; depth: number;
  baseX: number; baseY: number;
  brightness: number; targetBrightness: number;
  connections: number[];
  radius: number;
}

interface Particle {
  x: number; y: number; vx: number; vy: number;
  targetIdx: number; life: number; maxLife: number;
  active: boolean;
}

interface EnergyPulse {
  fromIdx: number; toIdx: number;
  progress: number; speed: number;
  active: boolean;
}

interface QueryText {
  text: string;
  phase: 'typing' | 'visible' | 'dissolving' | 'crossfade-out' | 'done';
  charIndex: number; timer: number;
  x: number; y: number;
  alpha: number;
  response: BrandResult | null;
  particles: { x: number; y: number; vx: number; vy: number; life: number }[];
}

interface BrandResult {
  name: string; cited: boolean;
  x: number; y: number; alpha: number; vy: number;
  timer: number; phase: 'appearing' | 'visible' | 'fading';
}

// ── Helpers ──
function lerp(a: number, b: number, t: number) { return a + (b - a) * t; }
function dist(x1: number, y1: number, x2: number, y2: number) {
  return Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2);
}
function rand(min: number, max: number) { return Math.random() * (max - min) + min; }

const HeroAnimation: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const rafRef = useRef<number>(0);
  const visibleRef = useRef(true);
  const mouseRef = useRef({ x: 0.5, y: 0.5 });
  const stateRef = useRef<{
    nodes: NetworkNode[];
    particles: Particle[];
    pulses: EnergyPulse[];
    queries: QueryText[];
    brands: BrandResult[];
    queryTimer: number;
    brandTimer: number;
    queryIndex: number;
    time: number;
    width: number;
    height: number;
    dpr: number;
    reducedMotion: boolean;
    staticDrawn: boolean;
  } | null>(null);

  // ── Initialize state ──
  const initState = useCallback((w: number, h: number, dpr: number) => {
    const cx = w * 0.5;
    const cy = h * 0.48;
    const nodes: NetworkNode[] = [];

    // Place nodes in concentric ellipses
    const rings = [
      { count: 6, rx: w * 0.08, ry: h * 0.08, depth: 0.6 },
      { count: 10, rx: w * 0.17, ry: h * 0.15, depth: 0.8 },
      { count: 12, rx: w * 0.27, ry: h * 0.22, depth: 1.0 },
    ];

    for (const ring of rings) {
      for (let i = 0; i < ring.count; i++) {
        const angle = (i / ring.count) * Math.PI * 2 + rand(-0.15, 0.15);
        const x = cx + Math.cos(angle) * ring.rx + rand(-15, 15);
        const y = cy + Math.sin(angle) * ring.ry + rand(-10, 10);
        nodes.push({
          x, y, baseX: x, baseY: y,
          depth: ring.depth,
          brightness: rand(0.05, 0.2),
          targetBrightness: 0,
          connections: [],
          radius: rand(2.5, 4.5),
        });
      }
    }

    // Build connections (nearest neighbors)
    for (let i = 0; i < nodes.length; i++) {
      const distances: { idx: number; d: number }[] = [];
      for (let j = 0; j < nodes.length; j++) {
        if (i === j) continue;
        distances.push({ idx: j, d: dist(nodes[i].x, nodes[j].x, nodes[i].y, nodes[j].y) });
      }
      distances.sort((a, b) => a.d - b.d);
      const connCount = Math.floor(rand(2, 5));
      for (let k = 0; k < Math.min(connCount, distances.length); k++) {
        if (!nodes[i].connections.includes(distances[k].idx)) {
          nodes[i].connections.push(distances[k].idx);
        }
        if (!nodes[distances[k].idx].connections.includes(i)) {
          nodes[distances[k].idx].connections.push(i);
        }
      }
    }

    // Pre-allocate particle pool
    const particles: Particle[] = [];
    for (let i = 0; i < MAX_PARTICLES; i++) {
      particles.push({ x: 0, y: 0, vx: 0, vy: 0, targetIdx: 0, life: 0, maxLife: 1, active: false });
    }

    // Pre-allocate pulse pool
    const pulses: EnergyPulse[] = [];
    for (let i = 0; i < MAX_PULSES; i++) {
      pulses.push({ fromIdx: 0, toIdx: 0, progress: 0, speed: 0, active: false });
    }

    const reducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

    stateRef.current = {
      nodes, particles, pulses,
      queries: [], brands: [],
      queryTimer: 0, brandTimer: 3,
      queryIndex: 0, time: 0,
      width: w, height: h, dpr,
      reducedMotion, staticDrawn: false,
    };
  }, []);

  // ── Spawn particle toward network ──
  const spawnParticle = useCallback((x: number, y: number) => {
    const s = stateRef.current;
    if (!s) return;
    for (const p of s.particles) {
      if (!p.active) {
        p.x = x; p.y = y;
        p.targetIdx = Math.floor(rand(0, s.nodes.length));
        p.vx = rand(-30, 30);
        p.vy = rand(-30, 30);
        p.life = 0;
        p.maxLife = rand(1.5, 3.5);
        p.active = true;
        return;
      }
    }
  }, []);

  // ── Spawn energy pulse ──
  const spawnPulse = useCallback((fromIdx: number) => {
    const s = stateRef.current;
    if (!s) return;
    const node = s.nodes[fromIdx];
    if (!node.connections.length) return;
    const toIdx = node.connections[Math.floor(rand(0, node.connections.length))];
    for (const pulse of s.pulses) {
      if (!pulse.active) {
        pulse.fromIdx = fromIdx;
        pulse.toIdx = toIdx;
        pulse.progress = 0;
        pulse.speed = rand(0.8, 1.6);
        pulse.active = true;
        return;
      }
    }
  }, []);

  // ── Update loop ──
  const update = useCallback((dt: number) => {
    const s = stateRef.current;
    if (!s) return;
    s.time += dt;

    // -- Parallax --
    const mx = (mouseRef.current.x - 0.5) * 2;
    const my = (mouseRef.current.y - 0.5) * 2;
    for (const node of s.nodes) {
      const px = mx * 12 * node.depth;
      const py = my * 8 * node.depth;
      node.x = lerp(node.x, node.baseX + px, dt * 3);
      node.y = lerp(node.y, node.baseY + py, dt * 3);
    }

    // -- Query text (centered, one at a time with crossfade to response) --
    s.queryTimer -= dt;
    if (s.queryTimer <= 0 && s.queries.length === 0) {
      const text = QUERIES[s.queryIndex % QUERIES.length];
      s.queryIndex++;
      s.queries.push({
        text, phase: 'typing', charIndex: 0, timer: 0,
        x: s.width * 0.5, y: s.height * 0.48,
        alpha: 1, response: null,
        particles: [],
      });
      s.queryTimer = rand(6, 9);
    }

    for (let qi = s.queries.length - 1; qi >= 0; qi--) {
      const q = s.queries[qi];
      q.timer += dt;

      if (q.phase === 'typing') {
        if (q.timer > 0.06) {
          q.timer = 0;
          q.charIndex++;
          if (q.charIndex >= q.text.length) {
            q.phase = 'visible';
            q.timer = 0;
          }
        }
      } else if (q.phase === 'visible') {
        if (q.timer > 1.5) {
          q.phase = 'crossfade-out';
          q.timer = 0;
          // Spawn dissolve particles from text center
          for (let p = 0; p < 20; p++) {
            spawnParticle(q.x + rand(-80, 80), q.y + rand(-8, 8));
          }
          // Prepare the brand response that will crossfade in
          const cited = Math.random() < 0.4;
          const name = cited
            ? CITED_BRANDS[Math.floor(rand(0, CITED_BRANDS.length))]
            : GHOST_BRANDS[Math.floor(rand(0, GHOST_BRANDS.length))];
          q.response = {
            name, cited,
            x: q.x, y: q.y + 4,
            alpha: 0, vy: 0,
            timer: 0, phase: 'appearing',
          };
        }
      } else if (q.phase === 'crossfade-out') {
        // Fade out query text
        q.alpha = Math.max(0, 1 - q.timer / 0.6);
        // Fade in brand response
        if (q.response) {
          q.response.alpha = Math.min(1, q.timer / 0.6);
          q.response.timer += dt;
          if (q.timer > 3.5) {
            // Fade everything out
            q.response.alpha = Math.max(0, q.response.alpha - dt * 1.2);
            if (q.response.alpha <= 0) {
              q.phase = 'done';
            }
          }
        }
      } else {
        s.queries.splice(qi, 1);
      }
    }

    // -- Particles --
    for (const p of s.particles) {
      if (!p.active) continue;
      p.life += dt;
      if (p.life >= p.maxLife) { p.active = false; continue; }

      const target = s.nodes[p.targetIdx];
      const dx = target.x - p.x;
      const dy = target.y - p.y;
      const d = Math.sqrt(dx * dx + dy * dy);

      // Seek behavior
      const seekStrength = Math.min(1, p.life / 0.5) * 200;
      p.vx += (dx / (d + 1)) * seekStrength * dt;
      p.vy += (dy / (d + 1)) * seekStrength * dt;

      // Damping
      p.vx *= 0.97;
      p.vy *= 0.97;

      p.x += p.vx * dt;
      p.y += p.vy * dt;

      // Collision with target node
      if (d < 15) {
        p.active = false;
        target.targetBrightness = Math.min(1, target.brightness + 0.4);
      }
    }

    // -- Node brightness --
    for (let i = 0; i < s.nodes.length; i++) {
      const node = s.nodes[i];
      // Lerp toward target then decay
      node.brightness = lerp(node.brightness, node.targetBrightness, dt * 4);
      node.targetBrightness *= (1 - dt * 1.5);
      // Ambient pulse
      node.brightness = Math.max(0.05 + Math.sin(s.time * 0.8 + i * 0.7) * 0.04, node.brightness);

      // Spawn energy pulse if bright enough
      if (node.brightness > 0.7 && Math.random() < dt * 2) {
        spawnPulse(i);
      }
    }

    // -- Energy pulses --
    for (const pulse of s.pulses) {
      if (!pulse.active) continue;
      pulse.progress += pulse.speed * dt;
      if (pulse.progress >= 1) {
        pulse.active = false;
        const targetNode = s.nodes[pulse.toIdx];
        targetNode.targetBrightness = Math.min(1, targetNode.brightness + 0.3);
      }
    }

    // -- Brand results --
    s.brandTimer -= dt;
    if (s.brandTimer <= 0 && s.brands.length < 3) {
      const cited = Math.random() < 0.35;
      const name = cited
        ? CITED_BRANDS[Math.floor(rand(0, CITED_BRANDS.length))]
        : GHOST_BRANDS[Math.floor(rand(0, GHOST_BRANDS.length))];
      s.brands.push({
        name, cited,
        x: s.width * 0.78 + rand(-20, 20),
        y: s.height * 0.2 + s.brands.length * 70,
        alpha: 0, vy: cited ? -0.3 : 0.3,
        timer: 0, phase: 'appearing',
      });
      s.brandTimer = rand(2, 4);
    }

    for (let bi = s.brands.length - 1; bi >= 0; bi--) {
      const b = s.brands[bi];
      b.timer += dt;

      if (b.phase === 'appearing') {
        b.alpha = Math.min(1, b.alpha + dt * 1.5);
        if (b.alpha >= 1) { b.phase = 'visible'; b.timer = 0; }
      } else if (b.phase === 'visible') {
        b.y += b.vy * dt * 10;
        if (b.timer > (b.cited ? 4 : 2.5)) {
          b.phase = 'fading';
          b.timer = 0;
        }
      } else if (b.phase === 'fading') {
        b.alpha -= dt * (b.cited ? 0.8 : 1.5);
        b.y += b.vy * dt * 15;
        if (b.alpha <= 0) {
          s.brands.splice(bi, 1);
        }
      }
    }
  }, [spawnParticle, spawnPulse]);

  // ── Render ──
  const render = useCallback((ctx: CanvasRenderingContext2D) => {
    const s = stateRef.current;
    if (!s) return;
    const { width: w, height: h, dpr } = s;

    ctx.save();
    ctx.scale(dpr, dpr);

    // Clear
    ctx.clearRect(0, 0, w, h);

    // Layer 1: Radial background glow
    const bgGrad = ctx.createRadialGradient(w * 0.5, h * 0.45, 0, w * 0.5, h * 0.45, w * 0.45);
    bgGrad.addColorStop(0, 'rgba(97, 0, 223, 0.08)');
    bgGrad.addColorStop(0.5, 'rgba(97, 0, 223, 0.03)');
    bgGrad.addColorStop(1, 'rgba(0, 0, 0, 0)');
    ctx.fillStyle = bgGrad;
    ctx.fillRect(0, 0, w, h);

    // Layer 2: Network connections
    ctx.lineWidth = 1;
    for (const node of s.nodes) {
      for (const ci of node.connections) {
        const other = s.nodes[ci];
        const avgBrightness = (node.brightness + other.brightness) / 2;
        ctx.strokeStyle = `rgba(168, 85, 247, ${avgBrightness * 0.3})`;
        ctx.beginPath();
        ctx.moveTo(node.x, node.y);
        ctx.lineTo(other.x, other.y);
        ctx.stroke();
      }
    }

    // Layer 3: Energy pulses
    ctx.globalCompositeOperation = 'lighter';
    for (const pulse of s.pulses) {
      if (!pulse.active) continue;
      const from = s.nodes[pulse.fromIdx];
      const to = s.nodes[pulse.toIdx];
      const px = lerp(from.x, to.x, pulse.progress);
      const py = lerp(from.y, to.y, pulse.progress);
      const intensity = Math.sin(pulse.progress * Math.PI);

      const pulseGrad = ctx.createRadialGradient(px, py, 0, px, py, 12);
      pulseGrad.addColorStop(0, `rgba(168, 85, 247, ${intensity * 0.9})`);
      pulseGrad.addColorStop(0.4, `rgba(139, 92, 246, ${intensity * 0.4})`);
      pulseGrad.addColorStop(1, 'rgba(139, 92, 246, 0)');
      ctx.fillStyle = pulseGrad;
      ctx.fillRect(px - 12, py - 12, 24, 24);
    }

    // Layer 4: Network nodes
    for (const node of s.nodes) {
      const b = node.brightness;
      // Outer glow
      const outerGrad = ctx.createRadialGradient(node.x, node.y, 0, node.x, node.y, node.radius * 6);
      outerGrad.addColorStop(0, `rgba(168, 85, 247, ${b * 0.3})`);
      outerGrad.addColorStop(1, 'rgba(168, 85, 247, 0)');
      ctx.fillStyle = outerGrad;
      ctx.fillRect(node.x - node.radius * 6, node.y - node.radius * 6, node.radius * 12, node.radius * 12);

      // Mid glow
      const midGrad = ctx.createRadialGradient(node.x, node.y, 0, node.x, node.y, node.radius * 3);
      midGrad.addColorStop(0, `rgba(192, 132, 252, ${b * 0.5})`);
      midGrad.addColorStop(1, 'rgba(192, 132, 252, 0)');
      ctx.fillStyle = midGrad;
      ctx.fillRect(node.x - node.radius * 3, node.y - node.radius * 3, node.radius * 6, node.radius * 6);

      // Core
      ctx.fillStyle = `rgba(233, 213, 255, ${0.3 + b * 0.7})`;
      ctx.beginPath();
      ctx.arc(node.x, node.y, node.radius, 0, Math.PI * 2);
      ctx.fill();
    }

    // Layer 5: Particles
    for (const p of s.particles) {
      if (!p.active) continue;
      const lifeRatio = 1 - p.life / p.maxLife;
      const alpha = lifeRatio * 0.8;
      const pGrad = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, 3);
      pGrad.addColorStop(0, `rgba(192, 132, 252, ${alpha})`);
      pGrad.addColorStop(1, 'rgba(192, 132, 252, 0)');
      ctx.fillStyle = pGrad;
      ctx.fillRect(p.x - 3, p.y - 3, 6, 6);
    }

    ctx.globalCompositeOperation = 'source-over';

    // Layer 6: Query text
    for (const q of s.queries) {
      if (q.phase === 'done') continue;

      let alpha = 1;
      if (q.phase === 'dissolving') {
        alpha = Math.max(0, 1 - q.timer / 0.8);
      }

      ctx.font = '16px "Inter", system-ui, sans-serif';
      ctx.fillStyle = `rgba(192, 132, 252, ${alpha * 0.9})`;
      ctx.shadowColor = 'rgba(168, 85, 247, 0.6)';
      ctx.shadowBlur = 8;

      const displayText = q.phase === 'typing'
        ? q.text.substring(0, q.charIndex)
        : q.text;

      ctx.fillText(displayText, q.x, q.y);

      // Blinking cursor
      if (q.phase === 'typing' && Math.floor(s.time * 3) % 2 === 0) {
        const textWidth = ctx.measureText(displayText).width;
        ctx.fillStyle = `rgba(168, 85, 247, ${alpha})`;
        ctx.fillRect(q.x + textWidth + 2, q.y - 13, 2, 16);
      }

      ctx.shadowColor = 'transparent';
      ctx.shadowBlur = 0;
    }

    // Layer 7: Brand results
    for (const b of s.brands) {
      if (b.alpha <= 0) continue;

      ctx.font = 'bold 15px "Inter", system-ui, sans-serif';

      if (b.cited) {
        // Purple glow + halo
        ctx.shadowColor = 'rgba(168, 85, 247, 0.7)';
        ctx.shadowBlur = 16;
        ctx.fillStyle = `rgba(192, 132, 252, ${b.alpha})`;
        ctx.fillText(b.name, b.x, b.y);

        // Halo ring
        ctx.shadowBlur = 0;
        ctx.shadowColor = 'transparent';
        const haloRadius = ctx.measureText(b.name).width / 2 + 15;
        ctx.strokeStyle = `rgba(168, 85, 247, ${b.alpha * 0.25})`;
        ctx.lineWidth = 1.5;
        ctx.beginPath();
        ctx.arc(b.x + ctx.measureText(b.name).width / 2, b.y - 5, haloRadius, 0, Math.PI * 2);
        ctx.stroke();

        // Checkmark
        const checkX = b.x - 18;
        const checkY = b.y - 4;
        ctx.strokeStyle = `rgba(34, 197, 94, ${b.alpha})`;
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(checkX, checkY);
        ctx.lineTo(checkX + 4, checkY + 4);
        ctx.lineTo(checkX + 10, checkY - 4);
        ctx.stroke();
      } else {
        // Ghost brand — dim with strikethrough
        ctx.shadowBlur = 0;
        ctx.shadowColor = 'transparent';
        ctx.fillStyle = `rgba(120, 120, 130, ${b.alpha * 0.5})`;
        ctx.fillText(b.name, b.x, b.y);

        // Strikethrough
        const tw = ctx.measureText(b.name).width;
        ctx.strokeStyle = `rgba(120, 120, 130, ${b.alpha * 0.3})`;
        ctx.lineWidth = 1;
        ctx.beginPath();
        ctx.moveTo(b.x, b.y - 5);
        ctx.lineTo(b.x + tw, b.y - 5);
        ctx.stroke();
      }
    }

    ctx.restore();
  }, []);

  // ── Canvas setup & animation loop ──
  useEffect(() => {
    const container = containerRef.current;
    const canvas = canvasRef.current;
    if (!container || !canvas) return;

    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    // Resize handler
    const resize = () => {
      const rect = container.getBoundingClientRect();
      const dpr = Math.min(window.devicePixelRatio || 1, 2);
      const w = rect.width;
      const h = CANVAS_HEIGHT;
      canvas.width = w * dpr;
      canvas.height = h * dpr;
      canvas.style.width = `${w}px`;
      canvas.style.height = `${h}px`;
      initState(w, h, dpr);
    };

    resize();

    // IntersectionObserver — pause when off-screen
    const observer = new IntersectionObserver(
      ([entry]) => { visibleRef.current = entry.isIntersecting; },
      { threshold: 0.05 }
    );
    observer.observe(container);

    // Mouse move for parallax
    const handleMouse = (e: MouseEvent) => {
      const rect = container.getBoundingClientRect();
      mouseRef.current = {
        x: (e.clientX - rect.left) / rect.width,
        y: (e.clientY - rect.top) / rect.height,
      };
    };
    container.addEventListener('mousemove', handleMouse);

    // Animation loop
    let lastTime = performance.now();

    const loop = (now: number) => {
      rafRef.current = requestAnimationFrame(loop);
      if (!visibleRef.current) return;

      const s = stateRef.current;
      if (!s) return;

      // Reduced motion — draw one static frame
      if (s.reducedMotion) {
        if (!s.staticDrawn) {
          // Set some nodes bright for static view
          for (let i = 0; i < s.nodes.length; i++) {
            s.nodes[i].brightness = 0.15 + (i % 3) * 0.1;
          }
          render(ctx);
          s.staticDrawn = true;
        }
        return;
      }

      const rawDt = (now - lastTime) / 1000;
      lastTime = now;
      const dt = Math.min(rawDt, DT_CAP);

      update(dt);
      render(ctx);
    };

    rafRef.current = requestAnimationFrame(loop);

    // Resize listener
    window.addEventListener('resize', resize);

    return () => {
      cancelAnimationFrame(rafRef.current);
      observer.disconnect();
      container.removeEventListener('mousemove', handleMouse);
      window.removeEventListener('resize', resize);
    };
  }, [initState, update, render]);

  return (
    <div ref={containerRef} className="relative w-full mb-20" style={{ height: `${CANVAS_HEIGHT}px` }}>
      <canvas
        ref={canvasRef}
        aria-hidden="true"
        className="absolute inset-0 w-full h-full"
      />

      {/* Glassmorphism overlay bar */}
      <div
        className="absolute bottom-0 left-0 right-0 flex flex-col sm:flex-row items-center justify-between gap-4 px-8 py-5 rounded-b-2xl"
        style={{
          background: 'rgba(0, 0, 0, 0.6)',
          backdropFilter: 'blur(12px)',
          WebkitBackdropFilter: 'blur(12px)',
          borderTop: '1px solid rgba(255, 255, 255, 0.06)',
        }}
      >
        <p className="text-white/80 text-sm sm:text-base font-light">
          Voici comment l'IA d{'\u00e9'}cide qui elle recommande. <span className="text-white font-medium">Et vous ?</span>
        </p>
        <button
          onClick={() => {
            const auditSection = document.getElementById('free-audit');
            if (auditSection) {
              auditSection.scrollIntoView({ behavior: 'smooth', block: 'center' });
            }
          }}
          className="btn-gradient text-sm px-6 py-2.5 flex items-center gap-2 whitespace-nowrap shadow-lg shadow-purple-600/20 hover:shadow-purple-600/30"
        >
          Analysez votre site <span aria-hidden="true">{'\u2192'}</span>
        </button>
      </div>
    </div>
  );
};

export default HeroAnimation;

