689→              title="Nouvel Audit AEO"
690→            >
691→              <Plus size={24} className="group-hover:rotate-90 transition-transform duration-300" />
692→            </button>
693→          )}
694→        </AppShell>
695→      )}
696→    </div>
697→    </ToastContext.Provider>
698→  );
699→};
