:root {
  --bg-base:        #000000;
  --bg-surface:     #0C0D0E;
  --bg-elevated:    #161718;
  --bg-overlay:     #1E1F21;
  --border-default: rgba(255, 255, 255, 0.08);
  --border-subtle:  rgba(255, 255, 255, 0.05);
  --border-strong:  rgba(255, 255, 255, 0.15);
  --text-primary:   #FFFFFF;
  --text-secondary: rgba(255, 255, 255, 0.7);
  --text-tertiary:  rgba(255, 255, 255, 0.4);
  --accent:         #6100DF;
  --accent-hover:   #7B2FE8;
  --accent-subtle:  rgba(97, 0, 223, 0.08);
  --accent-text:    #A855F7;
  --success:        #22C55E;
  --error:          #EF4444;
  color-scheme: dark;
}

html, body, #root {
  margin: 0;
  padding: 0;
  min-height: 100%;
  background-color: var(--bg-base);
  color: var(--text-secondary);
  font-family: 'Hikasami', 'Hikasami Static', 'Inter', system-ui, -apple-system, sans-serif;
  font-size: 16px;
  line-height: 1.4;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
  text-rendering: optimizeLegibility;
}

h1, h2, h3, h4, h5, h6 {
  font-family: 'Hikasami', 'Hikasami Static', 'Inter', system-ui, sans-serif;
  color: var(--text-primary);
}

::selection {
  background-color: var(--accent);
  color: white;
}

* {
  scrollbar-width: thin;
  scrollbar-color: rgba(255, 255, 255, 0.1) transparent;
}
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: rgba(255, 255, 255, 0.1); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: rgba(255, 255, 255, 0.2); }

*:focus-visible {
  outline: 2px solid var(--accent);
  outline-offset: 2px;
  border-radius: 4px;
}

@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(8px); }
  to { opacity: 1; transform: translateY(0); }
}
.page-enter { animation: fadeInUp 0.2s ease-out; }

.btn-gradient {
  background: #6100DF;
  padding: 0.75rem 2rem;
  border-radius: 8px;
  font-weight: 400;
  font-size: 1rem;
  color: #FFFFFF;
  transition: background-color 0.2s ease-out, transform 0.15s ease-out, box-shadow 0.2s ease-out;
}
.btn-gradient:hover {
  background: #7B2FE8;
  transform: translateY(-1px);
  box-shadow: 0 4px 20px -4px rgba(97, 0, 223, 0.5);
}
.btn-gradient:active {
  transform: scale(0.98);
}

@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: 0.01ms !important;
    animation-iteration-count: 1 !important;
    transition-duration: 0.01ms !important;
    scroll-behavior: auto !important;
  }
  .page-enter {
    animation: none !important;
    opacity: 1 !important;
    transform: none !important;
  }
}

